    let mut current = path.parent();

    while let Some(dir) = current {
        if dir == stop_at {
            break;
        }

        // Only remove if directory is empty
        if read_dir(dir)?.next().is_none() {
            remove_dir(dir)?;
        } else {
            break; // Stop as soon as we hit a non-empty directory
        }

        current = dir.parent();
    }

    Ok(())
}

